select t.department_id, t.employee_name, t.salary, row_number() over (partition by t.department_id order by t.salary desc) as dept_rank, sum(t.salary) over (partition by t.department_id) as dept_total, avg(t.salary) over () as company_avg, lag(t.salary, 1) over (partition by t.department_id order by t.hire_date) as prev_salary, sum(t.salary) over (partition by t.department_id order by t.hire_date rows between unbounded preceding and current row) as running_total from dbo.employees t
